cat > /tmp/sv-04e5de0ad26b42c5850e7b75c1363633/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "../build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

void Walk(BaseNode node, string currentProject = "")
{
    if (node is Project p) currentProject = p.Name;
    if (node is Target t && node.Parent is Project tp) currentProject = tp.Name;

    if (node is Error err)
    {
        errors.Add((currentProject, err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? err.ToString(), err.Subcategory ?? ""));
    }
    if (node is Warning warn)
    {
        warnings.Add((currentProject, warn.File ?? "", warn.LineNumber, warn.ColumnNumber, warn.Code ?? "", warn.Text ?? warn.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Walk(bn, currentProject);
        }
    }
}

Walk(build);

Console.WriteLine($"=== ERRORS ({errors.Count} total) ===");
Console.WriteLine();

// Group errors by project
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = !string.IsNullOrEmpty(e.File) ? $"{e.File}({e.Line},{e.Col})" : "(no location)";
        Console.WriteLine($"  {e.Code}: {e.Message}");
        Console.WriteLine($"    at {location}");
    }
    Console.WriteLine();
}

Console.WriteLine($"=== WARNINGS ({warnings.Count} total) ===");
Console.WriteLine();
// Show only non-trivial warnings
var importantWarnings = warnings.Where(w => !string.IsNullOrEmpty(w.Code)).GroupBy(w => w.Code).OrderBy(g => g.Key);
foreach (var group in importantWarnings)
{
    Console.WriteLine($"  {group.Key} ({group.Count()}x): {group.First().Message}");
    if (group.Count() > 1)
    {
        foreach (var w in group.Skip(0).Take(5))
        {
            Console.WriteLine($"    in {w.Project} at {w.File}({w.Line},{w.Col})");
        }
        if (group.Count() > 5) Console.WriteLine($"    ... and {group.Count()-5} more");
    }
}

// Also look at project build results
Console.WriteLine();
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
void WalkProjects(BaseNode node)
{
    if (node is Project proj)
    {
        Console.WriteLine($"  {proj.Name} -> Succeeded: {proj.Succeeded}");
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) WalkProjects(bn);
        }
    }
}
WalkProjects(build);
