cat > /tmp/sv-04e5de0ad26b42c5850e7b75c1363633/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "../build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors with full context
var errors = new List<(string Project, string TargetFramework, string File, int Line, int Col, string Code, string Message)>();

void Walk(BaseNode node, string currentProject = "", string currentTF = "")
{
    if (node is Project p) 
    {
        currentProject = p.Name;
        currentTF = p.TargetFramework ?? "";
    }

    if (node is Error err)
    {
        errors.Add((currentProject, currentTF, err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? err.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Walk(bn, currentProject, currentTF);
        }
    }
}

Walk(build);

Console.WriteLine($"=== ALL ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"  [{e.Project} ({e.TargetFramework})] {e.Code}: {e.Message}");
    Console.WriteLine($"    File: {e.File}({e.Line},{e.Col})");
}

// Now look at project references and NuGet packages
Console.WriteLine();
Console.WriteLine("=== PROJECT STRUCTURE ===");
void WalkStructure(BaseNode node, int depth = 0)
{
    if (node is Project proj && depth < 3)
    {
        var indent = new string(' ', depth * 2);
        Console.WriteLine($"{indent}Project: {proj.Name} (TF: {proj.TargetFramework})");

        // Look for items in the project
        foreach (var child in proj.Children)
        {
            if (child is Folder folder)
            {
                if (folder.Name == "Items" || folder.Name == "AddItem")
                {
                    foreach (var itemGroup in folder.Children)
                    {
                        if (itemGroup is TreeNode tn && (tn.Name?.Contains("PackageReference") == true || tn.Name?.Contains("ProjectReference") == true))
                        {
                            Console.WriteLine($"{indent}  {tn.Name}:");
                            foreach (var item in tn.Children)
                            {
                                Console.WriteLine($"{indent}    - {item}");
                            }
                        }
                    }
                }
            }
        }
    }
    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) WalkStructure(bn, node is Project ? depth + 1 : depth);
        }
    }
}
WalkStructure(build);

// Also look at source files that were compiled (to find the problematic UserService.cs)
Console.WriteLine();
Console.WriteLine("=== SEARCHING FOR SOURCE FILE CONTENT ===");
void SearchSourceFiles(BaseNode node, string project = "")
{
    if (node is Project p) project = p.Name;

    if (node is Item item && item.Name?.Contains("UserService") == true)
    {
        Console.WriteLine($"  Found item: {item.Name} in {project}");
    }
    if (node is Message msg && msg.Text?.Contains("UserService") == true)
    {
        Console.WriteLine($"  Message in {project}: {msg.Text?.Substring(0, Math.Min(200, msg.Text.Length))}");
    }

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) SearchSourceFiles(bn, project);
        }
    }
}
SearchSourceFiles(build);

// Show all compiled source files for Services.csproj
Console.WriteLine();
Console.WriteLine("=== COMPILATION ITEMS FOR SERVICES PROJECT ===");
void FindCompileItems(BaseNode node, string project = "", bool inServicesProject = false)
{
    if (node is Project p) 
    {
        project = p.Name;
        inServicesProject = p.Name == "Services.csproj";
    }

    if (inServicesProject && node is NamedNode nn)
    {
        var name = nn.Name ?? "";
        if (name.Contains("Compile") || name.Contains("Reference") || name.Contains("Package"))
        {
            if (node is TreeNode tn2 && tn2.Children.Count > 0)
            {
                Console.WriteLine($"  {nn.Name}:");
                foreach (var child in tn2.Children.Take(20))
                {
                    Console.WriteLine($"    {child}");
                }
            }
        }
    }

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) FindCompileItems(bn, project, inServicesProject);
        }
    }
}
FindCompileItems(build);
