void Walk(BaseNode node, string currentProject = "", string currentTF = "")
{
    if (node is Project p) 
    {
        currentProject = p.Name;
        currentTF = p.TargetFramework ?? "";
    }

    if (node is Error err)
    {
        errors.Add((currentProject, currentTF, err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? err.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Walk(bn, currentProject, currentTF);
        }
    }
}

Walk(build);

Console.WriteLine($"=== ALL ERRORS ({errors.Count}) ===");
