Console.WriteLine();

// Collect all errors with full context
var errors = new List<(string Project, string TargetFramework, string File, int Line, int Col, string Code, string Message)>();

void Walk(BaseNode node, string currentProject = "", string currentTF = "")
{
    if (node is Project p) 
    {
        currentProject = p.Name;
        currentTF = p.TargetFramework ?? "";
    }

    if (node is Error err)
    {
        errors.Add((currentProject, currentTF, err.File ?? "", err.LineNumber, err.ColumnNumber, err.Code ?? "", err.Text ?? err.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Walk(bn, currentProject, currentTF);
        }
    }
}

Walk(build);

Console.WriteLine($"=== ALL ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"  [{e.Project} ({e.TargetFramework})] {e.Code}: {e.Message}");
    Console.WriteLine($"    File: {e.File}({e.Line},{e.Col})");
}

// Dump full tree structure to find project references 
Console.WriteLine();
Console.WriteLine("=== TREE DUMP (first few levels) ===");
void DumpTree(BaseNode node, int depth = 0, int maxDepth = 4)
{
    if (depth > maxDepth) return;
    var indent = new string(' ', depth * 2);
    var type = node.GetType().Name;

    if (node is Project proj)
    {
        Console.WriteLine($"{indent}[{type}] {proj.Name} (TF: {proj.TargetFramework})");
    }
    else if (node is Target tgt)
    {
        // Only show interesting targets
        if (tgt.Name?.Contains("Resolve") == true || tgt.Name?.Contains("Compile") == true || tgt.Name?.Contains("Reference") == true)
            Console.WriteLine($"{indent}[{type}] {tgt.Name}");
        else return;
    }
    else if (node is Folder folder)
    {
        Console.WriteLine($"{indent}[{type}] {folder.Name}");
    }
    else if (node is Error err)
    {
        Console.WriteLine($"{indent}[{type}] {err.Code}: {err.Text?.Substring(0, Math.Min(100, err.Text?.Length ?? 0))}");
    }
    else if (depth <= 2)
    {
        Console.WriteLine($"{indent}[{type}] {node}");
    }
    else return;

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) DumpTree(bn, depth + 1, maxDepth);
        }
    }
}
