cat > /tmp/sv-04e5de0ad26b42c5850e7b75c1363633/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("../build.binlog");

// Find all Project nodes and check for errors + build result
Console.WriteLine("=== DETAILED PROJECT STATUS ===");
void WalkProjects(BaseNode node, int depth = 0)
{
    if (node is Project proj)
    {
        var errors = new System.Collections.Generic.List<string>();
        void CollectErrors(BaseNode n) {
            if (n is Error e) errors.Add($"{e.Code}: {e.Text}");
            if (n is TreeNode t) foreach (var c in t.Children) if (c is BaseNode b) CollectErrors(b);
        }
        CollectErrors(proj);

        // Check if this is a Build (not Restore) invocation
        var targets = "";
        if (proj.Children.OfType<Folder>().FirstOrDefault(f => f.Name == "Entry targets") is Folder entryFolder)
        {
            targets = string.Join(", ", entryFolder.Children.Select(c => c.ToString()));
        }

        Console.WriteLine($"  Project: {proj.Name} (TF: {proj.TargetFramework}) Targets: [{targets}]");
        if (errors.Count > 0)
        {
            foreach (var e in errors)
                Console.WriteLine($"    ERROR: {e}");
        }
        else
        {
            Console.WriteLine($"    (no errors)");
        }
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) WalkProjects(bn, node is Project ? depth + 1 : depth);
        }
    }
}
WalkProjects(build);

// Check if Api.csproj was skipped due to Services failure
Console.WriteLine();
Console.WriteLine("=== SEARCHING FOR BUILD SKIP/FAILURE MESSAGES ===");
void FindSkipMessages(BaseNode node, string project = "")
{
    if (node is Project p) project = p.Name;
    if (node is Message msg)
    {
        var text = msg.Text ?? "";
        if (text.Contains("skip") || text.Contains("Skip") || text.Contains("not built") || 
            text.Contains("depend") || text.Contains("failed") || text.Contains("Failed") ||
            text.Contains("not building") || text.Contains("previously"))
        {
            Console.WriteLine($"  [{project}] {text.Substring(0, Math.Min(300, text.Length))}");
        }
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn) FindSkipMessages(bn, project);
        }
    }
}
FindSkipMessages(build);
